/// State machine for TUI modes.
#[derive(Debug, Clone, PartialEq)]
pub enum TuiMode {
    Chat,
    Overlay,
    Select,
    Permission,
    CommandPalette,
    DiffViewer,
    SessionTree,
    Onboarding,
}

impl TuiMode {
    /// Returns valid next states from current state.
    pub fn valid_transitions(&self) -> Vec<TuiMode> {
        match self {
            // Chat can go to many modes
            TuiMode::Chat => vec![
                TuiMode::CommandPalette,
                TuiMode::Onboarding,
            ],
            // Modal modes return to Chat
            TuiMode::Overlay => vec![TuiMode::Chat],
            TuiMode::Select => vec![TuiMode::Chat],
            TuiMode::Permission => vec![TuiMode::Chat],
            TuiMode::CommandPalette => vec![TuiMode::Chat],
            TuiMode::DiffViewer => vec![TuiMode::Chat],
            TuiMode::SessionTree => vec![TuiMode::Chat],
            // Onboarding returns to Chat on completion
            TuiMode::Onboarding => vec![TuiMode::Chat],
        }
    }

    /// Check if transition to target is valid.
    pub fn can_transition_to(&self, target: &TuiMode) -> bool {
        self.valid_transitions().contains(target)
    }
}
